import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.C_beXv0I.js";const p=JSON.parse('{"title":"Credits","description":"","frontmatter":{},"headers":[],"relativePath":"about/credits.md","filePath":"about/credits.md","lastUpdated":1783011651000}'),s={name:"about/credits.md"};function i(n,e,d,l,c,u){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="credits" tabindex="-1">Credits <a class="header-anchor" href="#credits" aria-label="Permalink to &quot;Credits&quot;">​</a></h1><p>Muster&#39;s design was inspired by <a href="https://atomic.alonso.network/" target="_blank" rel="noreferrer">atomic-claude</a>, <a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">superpowers</a>, and gsd-core. It vendors a curated set of MIT-licensed skills and agents, with every source and item recorded for attribution.</p><h2 id="vendored-sources" tabindex="-1">Vendored sources <a class="header-anchor" href="#vendored-sources" aria-label="Permalink to &quot;Vendored sources&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>License</th><th>Provides</th></tr></thead><tbody><tr><td>obra/superpowers</td><td>MIT</td><td>Brainstorming, planning, TDD, code-review, debugging, verification skills</td></tr><tr><td>wshobson/agents</td><td>MIT</td><td>Software and knowledge-work agents and skills across many specialties</td></tr><tr><td>open-gsd/gsd-core</td><td>MIT</td><td>Plan, execute, and verify workflow phases</td></tr></tbody></table><p>Every vendored item is listed in <code>vendor/manifest.yaml</code> with its repository, license, and ref, and provenance is written into <a href="https://github.com/Adnova-Group/muster/blob/main/NOTICE" target="_blank" rel="noreferrer">NOTICE</a>.</p><h2 id="clean-room-specialists" tabindex="-1">Clean-room specialists <a class="header-anchor" href="#clean-room-specialists" aria-label="Permalink to &quot;Clean-room specialists&quot;">​</a></h2><p>Alongside the vendored material, Muster ships its own specialists in <code>plugin/agents/</code>, authored fresh from the role concept:</p><ul><li><strong>muster-surgeon</strong>: precise 1-2 file edits</li><li><strong>muster-builder</strong>: a cohesive vertical slice</li><li><strong>muster-reviewer</strong>: verdict-emitting review</li><li><strong>muster-investigator</strong>: read-only locator</li><li><strong>muster-strategist</strong>: heavyweight reasoning</li><li><strong>muster-improver</strong>: read-only post-run retrospective that proposes self-improvement edits</li></ul><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>Muster is licensed under Apache-2.0. See <a href="https://github.com/Adnova-Group/muster/blob/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a> and <a href="https://github.com/Adnova-Group/muster/blob/main/NOTICE" target="_blank" rel="noreferrer">NOTICE</a>.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>Contributions are welcome. See <a href="https://github.com/Adnova-Group/muster/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">CONTRIBUTING.md</a> to get started.</p>',12)])])}const m=t(s,[["render",i]]);export{p as __pageData,m as default};
